INSERT INTO `jurnal_guru` VALUES (363, 248, 57, 'Amy Safitri', 11, 21, 'IPAS', '', '', '', '28-07-2025', '16:48:24', '10:45', '12:45', 'Peserta didik mempelajari salah satu contoh perubahan energi dari energi cahaya menjadi energi kimia, yaitu proses fotosintesis. Kemudian, peserta didik mengerjakan LKPD guna menumbuhkan pemahaman mereka lebih dalam mengenai proses fotosintesis.', 'BAB 1. Perubahan Bentuk Energi', 1, '28-07-2025', 'Ganjil', 90, '2025/2026', '52785e21-4fac-4348-ae75-9bcfc9268d03');
