INSERT INTO `jurnal_guru` VALUES (1453, 251, 57, 'Amy Safitri', 11, 16, 'Pendidikan Pancasila', '', '', '', '01-09-2025', '20:00:47', '13:30', '15:00', 'Peserta didik mengetahui struktur pemerintahan di kabupaten/kota.', 'BAB 1. Mengenal Lingkungan Sekitar', 1, '07-09-2025', 'Ganjil', 90, '2025/2026', '1eeb5197-13a8-4a71-ae3c-38015ffa25bd');
INSERT INTO `jurnal_guru` VALUES (1454, 276, 57, 'Amy Safitri', 11, 7, 'Bahasa Indonesia', '', '', '', '02-09-2025', '20:03:05', '08:15', '09:15', 'Peserta didik belajar memahami isi teks yang dibacakan, yaitu dengan secara berkelompok membuat paragraf berisi ciri-ciri suatu peralatan rumah tangga. Kemudian perwakilan kelompok membacakan ciri-ciri yang telah dibuat agar ditebak oleh kelompok lain.', 'BAB 2. Di Bawah Atap', 1, '07-09-2025', 'Ganjil', 90, '2025/2026', '9eb14ce4-2b36-4d11-a842-cc88b9729458');
INSERT INTO `jurnal_guru` VALUES (1455, 277, 57, 'Amy Safitri', 11, 7, 'Bahasa Indonesia', '', '', '', '02-09-2025', '20:04:37', '10:45', '11:45', 'Peserta didik dapat membuat kalimat dengan menggunakan kata dasar yang diberi imbuhan Me-. Peserta didik mendapatkan 3 kata dasar dari guru, kemudian menuliskan imbuhan dan membuat contoh kalimatnya di buku tulis.', 'BAB 2. Di Bawah Atap', 1, '07-09-2025', 'Ganjil', 90, '2025/2026', '41560753-aafb-481c-9d8b-59b5e828dcd5');
INSERT INTO `jurnal_guru` VALUES (1456, 278, 57, 'Amy Safitri', 11, 3, 'Bahasa Jawa', '', '', '', '03-09-2025', '20:05:20', '08:15', '09:15', 'Peserta didik membuat Geguritan. Kemudian beberapa peserta didik membacakan Geguritan yang telah dibuat di depan kelas.', 'BAB 1. Guyub Rukun', 1, '07-09-2025', 'Ganjil', 90, '2025/2026', '857f3ea5-5740-4ab0-8dec-5847c82d7f04');
INSERT INTO `jurnal_guru` VALUES (1457, 279, 57, 'Amy Safitri', 11, 15, 'Matematika', '', '', '', '03-09-2025', '20:07:22', '10:45', '12:45', 'Peserta didik mengulas kembali perkalian satuan 1 - 9, yaitu dengan melakukan permainan tim memnjawab perkalian.\nKemudian peserta didik memahami cara menghitung perkalian puluhan dengan satuan menggunakan cara bersusun.', 'BAB 1. Bilangan Cacah sampai 10.000', 1, '07-09-2025', 'Ganjil', 90, '2025/2026', 'ab26f20e-646a-4c37-ac88-ddfdb0e81e1d');
