INSERT INTO `jurnal_guru` VALUES (3162, 356, 59, 'Zafar Sigit, S.Pd.', 1, 9, 'Pendidikan Agama Islam', '', '', '', '12-11-2025', '10:46:15', '09:15', '10:15', 'Memahami kalimat syahadatain\r\nMengerjakan soal uji kompetensi', 'Mengetahui rukun islam', 1, '13-11-2025', 'Ganjil', 90, '2025/2026', '68bd5fb0-d39e-4b36-8923-44160aa025c0');
INSERT INTO `jurnal_guru` VALUES (3163, 248, 57, 'Amy Safitri', 11, 21, 'IPAS', '', '', '', '03-11-2025', '10:59:00', '10:45', '12:45', 'Murid mengethahui ragam bentang alam yang ada di Indonesia, baik bentang alam daratan maupun perairan.', 'BAB 3. Disini Tempat Tinggalku', 1, '13-11-2025', 'Ganjil', 90, '2025/2026', 'cc0d5dc5-1d65-4be1-9e3d-e34cfe83906e');
INSERT INTO `jurnal_guru` VALUES (3164, 251, 57, 'Amy Safitri', 11, 16, 'Pendidikan Pancasila', '', '', '', '03-11-2025', '11:01:40', '13:30', '15:00', 'Murid mengelompokkan peraturan-peraturan yang ada di sekitar mereka ke dalam 2 enis, yaitu peraturan tertulis dan peraturan tidak tertulis.', 'BAB 2. Aku Anak yang Disiplin', 1, '13-11-2025', 'Ganjil', 90, '2025/2026', '3ace5b0b-e438-4dba-86d7-3a6ae8a99458');
INSERT INTO `jurnal_guru` VALUES (3165, 276, 57, 'Amy Safitri', 11, 7, 'Bahasa Indonesia', '', '', '', '04-11-2025', '11:04:15', '08:15', '09:15', 'Murid secara berkelompok menuliskan rute perjalanan dalam bentuk paragraf. Setiap kelompok mendapatkan cerita yang berbeda-beda dalam menentukan rute perjalanan.', 'BAB 3. Lihat Sekitar', 1, '13-11-2025', 'Ganjil', 90, '2025/2026', 'c8c0eb8a-f961-44af-88c8-dd3f68c2f71d');
INSERT INTO `jurnal_guru` VALUES (3166, 277, 57, 'Amy Safitri', 11, 7, 'Bahasa Indonesia', '', '', '', '04-11-2025', '11:05:37', '10:45', '11:45', 'Murid secara berkelompok mempresentasikan hasil kerja mereka membuat paragraf tentang rute perjalanan. Kemudian murid memahami bahwa paragraf yang telah mereka buat merupakan paragraf deskripsi.', 'BAB 3. Lihat Sekitar', 1, '13-11-2025', 'Ganjil', 90, '2025/2026', '7e5b8837-aa79-4a93-a885-e8de08218890');
INSERT INTO `jurnal_guru` VALUES (3167, 278, 57, 'Amy Safitri', 11, 3, 'Bahasa Jawa', '', '', '', '05-11-2025', '11:07:29', '08:15', '09:15', 'Murid memahami adanya unggah ungguh basa dalam teks pacelathon. Kemudian menulis materi unggah ungguh basa.', 'BAB 2. Gemi Nggunakake Energi', 1, '13-11-2025', 'Ganjil', 90, '2025/2026', 'be022ee7-30c7-4984-a13c-1ced8301a353');
INSERT INTO `jurnal_guru` VALUES (3168, 279, 57, 'Amy Safitri', 11, 15, 'Matematika', '', '', '', '05-11-2025', '11:08:37', '10:45', '12:45', 'Murid mengubah pecahan persepulhan dan perseraturan menjadi pecahan desimal. Kemudian sebaliknya, mengubah pecahan desimal menjadi pecahan persepuluhan dan perseratusan.', 'BAB 2. Pecahan', 1, '13-11-2025', 'Ganjil', 90, '2025/2026', 'ff761964-64a2-4b7e-97e8-3584699a68bf');
INSERT INTO `jurnal_guru` VALUES (3169, 280, 57, 'Amy Safitri', 11, 14, 'Seni Budaya', '', '', '', '06-11-2025', '11:10:11', '11:45', '12:45', 'Murid menggambar unsur-unsur seni rupa (warna dan tekstur)', 'BAB 3. Mengkreasikan Karya Seni Dua Dimensi dan Tiga Dimensi', 1, '13-11-2025', 'Ganjil', 90, '2025/2026', '24e11ac1-26d9-4a60-9b51-0ab04c8dbff7');
INSERT INTO `jurnal_guru` VALUES (3170, 471, 57, 'Amy Safitri', 11, 25, 'life skill', '', '', '', '07-11-2025', '11:10:48', '08:45', '10:15', 'Murid menyimak hasil tugas video menyetrika yang telah dilakukan di rumah masing-masing.', 'Perawatan Pakaian', 1, '13-11-2025', 'Ganjil', 90, '2025/2026', '37352c85-a651-41e1-8271-8a4ae8b09dac');
INSERT INTO `jurnal_guru` VALUES (3171, 248, 57, 'Amy Safitri', 11, 21, 'IPAS', '', '', '', '10-11-2025', '11:13:14', '10:45', '12:45', 'Murid memahami adanya keanekaragamn hayati, meliputi tingkatan keanekaragaman hayati dan peserbaran flora dan fauna di tiga wilayah Indonesia. Kemudian menulis materi keanekaragaman hayati.', 'BAB 5. Keanearagaman Hayati', 1, '13-11-2025', 'Ganjil', 90, '2025/2026', '839200dc-e89b-4fc0-844b-d34323325379');
INSERT INTO `jurnal_guru` VALUES (3172, 251, 57, 'Amy Safitri', 11, 16, 'Pendidikan Pancasila', '', '', '', '10-11-2025', '11:14:00', '13:30', '15:00', 'Murid memahami adanya perbedaan antara Hak dan Kwajiban sebagai murid di sekolah, maupun sebagai angggota keluarga di rumah.', 'BAB 2. Aku Anak yang Disiplin', 1, '13-11-2025', 'Ganjil', 90, '2025/2026', '94269c1c-77ae-4c76-a360-f822e6632baa');
