INSERT INTO `jurnal_guru` VALUES (3601, 276, 57, 'Amy Safitri', 11, 7, 'Bahasa Indonesia', '', '', '', '11-11-2025', '18:04:11', '08:15', '09:15', 'Masing-masing murid mendapatkan lembar kerja dengan stiap murid mendapat soal yang berbeda. Kemudian murid menuliskan paragraf deskripsi dari objek, tempat atau peristiwa yang telah diperoleh dengan mandiri.', 'BAB 3. Lihat Sekitar', 1, '15-11-2025', 'Ganjil', 90, '2025/2026', '93a7e203-029e-4e5f-8d96-2cf302e018dc');
INSERT INTO `jurnal_guru` VALUES (3602, 277, 57, 'Amy Safitri', 11, 7, 'Bahasa Indonesia', '', '', '', '11-11-2025', '18:05:34', '10:45', '11:45', 'Murid secara bergantian mempresentasikan hasil kerja mereka dalam membuat paragraf deskripsi.', 'BAB 3. Lihat Sekitar', 1, '15-11-2025', 'Ganjil', 90, '2025/2026', '3535b02f-e560-4186-b264-858f8b2d0f04');
INSERT INTO `jurnal_guru` VALUES (3603, 278, 57, 'Amy Safitri', 11, 3, 'Bahasa Jawa', '', '', '', '12-11-2025', '18:06:16', '08:15', '09:15', 'Murid mengetahui cara menyusun teks pacelathon serta mengetahui hal-hal yang perlu diperhatikan dalam memperagakan teks pacelathon.', 'BAB 2. Gemi Nggunakake Energi', 1, '15-11-2025', 'Ganjil', 90, '2025/2026', '35f0138d-8eed-4909-8dbf-38d4dd1ba257');
INSERT INTO `jurnal_guru` VALUES (3604, 279, 57, 'Amy Safitri', 11, 15, 'Matematika', '', '', '', '12-11-2025', '18:07:18', '10:45', '12:45', 'Murid dapat mengubah pecahan perseratusan menjadi bentuk persen, dan sebalaiknya yaitu dapat mengubah bilangan bentuk persen menjadi pecahan perseratusan.', 'BAB 2. Pecahan', 1, '15-11-2025', 'Ganjil', 90, '2025/2026', '53881e21-d469-41f6-b8b2-7f5705a0cb43');
INSERT INTO `jurnal_guru` VALUES (3605, 280, 57, 'Amy Safitri', 11, 14, 'Seni Budaya', '', '', '', '13-11-2025', '18:09:29', '11:45', '12:45', 'Murid mengetahui adanya komposisi-komposisi dalam seni rupa. Kemudian murid praktis menggambar komposisi simetris, yaitu dengan menggambar separuh gambar dari gambar yang sudah ada agar menjadi gambar yang utuh.', 'BAB 3. Mengkreasikan karya seni rupa dua dimensi dan tiga dimensi', 1, '15-11-2025', 'Ganjil', 90, '2025/2026', '93bb4d6b-3497-4340-84af-6ead48dbfaec');
INSERT INTO `jurnal_guru` VALUES (3606, 471, 57, 'Amy Safitri', 11, 25, 'life skill', '', '', '', '14-11-2025', '18:10:08', '08:45', '10:15', 'Murid melakukan outing class ke UD. Shabrina, dimana mereka mengetahui proses produksi roti.', 'Outing Class', 1, '15-11-2025', 'Ganjil', 90, '2025/2026', '5138f1eb-b5dd-4fc9-8149-043b982c38a0');
