INSERT INTO `jurnal_guru` VALUES (3608, 350, 48, 'Dennika Tasya Maghfiroh, S.Pd', 7, 14, 'Seni Budaya', '', '', '', '13-11-2025', '20:16:33', '11:45', '12:45', 'siswa menggambar garis simetris pada gambar ', '', 1, '15-11-2025', 'Ganjil', 90, '2025/2026', '12f1ba20-922c-4136-bb54-bdd78c4561b7');
