INSERT INTO `jurnal_guru` VALUES (5992, 277, 57, 'Amy Safitri, S.Pd', 11, 7, 'Bahasa Indonesia', '', '', '', '10-02-2026', '20:37:51', '10:45', '11:45', 'Murid melakukan mini games yaitu berpindah tempat duduk setiap 90 detik. Pada setiap tempat duduk sudah terdapat sebuah kalimat, lalu murid harus mengelompokkan kalimat tersebut ke dalam kalimat efektif atau tidak efektif.', 'Satu Titik', 1, '18-02-2026', 'Genap', 90, '2025/2026', '0c54c5d4-247d-4ff7-8ebf-1a9d9448b8c9');
INSERT INTO `jurnal_guru` VALUES (5993, 278, 57, 'Amy Safitri, S.Pd', 11, 3, 'Bahasa Jawa', '', '', '', '11-02-2026', '20:38:38', '08:15', '09:15', 'Murid mengenal sandangan pada huruf aksara jawa', 'Gegayuhanku', 1, '18-02-2026', 'Genap', 90, '2025/2026', '8f0a4f96-3f59-4b4b-a36b-96237757031c');
INSERT INTO `jurnal_guru` VALUES (5994, 279, 57, 'Amy Safitri, S.Pd', 11, 15, 'Matematika', '', '', '', '11-02-2026', '20:41:50', '10:45', '12:45', 'Murid mengenal cara menghitung luas satuan tidak baku dan luas satuan baku. Mereka belajar bersama dengan menggunakan aplikasi penyusun luas satuan baku pada smart tv.', 'Pengukuran Luas dan Volume', 1, '18-02-2026', 'Genap', 90, '2025/2026', 'dd73f1cf-17ef-4eaa-810c-85a9750998dd');
INSERT INTO `jurnal_guru` VALUES (5995, 280, 57, 'Amy Safitri, S.Pd', 11, 14, 'Seni Budaya', '', '', '', '12-02-2026', '20:43:48', '11:45', '12:45', 'Murid mngaplikasikan cara membentuk sebuah bangun ruang, yaitu praktik membentuk kubus dari jaring-jaringnya sehingga dapat membentuk miniatur kakbah.', 'Membuat Konstruksi Sederhana', 1, '18-02-2026', 'Genap', 90, '2025/2026', 'd75daec5-3637-4875-b55b-6b9b0727a50b');
INSERT INTO `jurnal_guru` VALUES (5996, 471, 57, 'Amy Safitri, S.Pd', 11, 25, 'life skill', '', '', '', '13-02-2026', '20:45:08', '08:45', '10:15', 'Murid menyaksikan video dan penjelasan dari guru mengenai tujuan dan cara mencuci peralatan makan dengan baik. Lalu mendapat tugas mandiri untuk membuat video mencuci peralatan makan di rumah.', '', 1, '18-02-2026', 'Genap', 90, '2025/2026', '37adc761-816d-4249-866a-607bd0959bd7');
