INSERT INTO `jurnal_guru` VALUES (8600, 248, 57, 'Amy Safitri, S.Pd', 11, 21, 'IPAS', '', '', '', '11-05-2026', '20:56:51', '10:45', '12:45', 'Murid mempelajari tentang hubungan gas karbondioksida dengan pemanasan global. Mereka dapat menyebutkan kegiatan manusia yang menimbulkan jejak karbon, serta dapat menyebutkan langkah-langkah mengurangi jejak karbon.', 'BAB 8. Menjadi Pahlawan Lingkungan', 1, '11-05-2026', 'Genap', 90, '2025/2026', 'eaf081e6-9b74-4424-88e3-f3cfd3a4a69a');
INSERT INTO `jurnal_guru` VALUES (8601, 251, 57, 'Amy Safitri, S.Pd', 11, 16, 'Pendidikan Pancasila', '', '', '', '11-05-2026', '20:58:29', '13:30', '15:00', 'Murid mempelajari karakter-karakter perumus pancasila. Kemudian mengerjakan soal evaluasi di LKS serta mengoreksinya bersama-sama.', 'BAB 4. Negaraku Indonesia', 1, '11-05-2026', 'Genap', 90, '2025/2026', '692e5583-d863-4ce2-a0cd-67d234f84043');
INSERT INTO `jurnal_guru` VALUES (8602, 471, 57, 'Amy Safitri, S.Pd', 11, 25, 'life skill', '', '', '', '08-05-2026', '20:58:47', '08:45', '10:15', 'Murid belajar mengupas buah dengan menggunakan pisau kupas.', '', 1, '11-05-2026', 'Genap', 90, '2025/2026', '1be5e9c7-721e-4bf0-a334-8e3bbf34ffa2');
INSERT INTO `jurnal_guru` VALUES (8603, 280, 57, 'Amy Safitri, S.Pd', 11, 14, 'Seni Budaya', '', '', '', '07-05-2026', '21:01:49', '11:45', '12:45', 'Murid mempelajari contoh-contoh karya seni rupa 2D dan 3D dengan cara mengelompokkannya melalui sebuah LKPD.', 'BAB 6. Membuat Karya Seni yang Berdampak', 1, '11-05-2026', 'Genap', 90, '2025/2026', '30894a09-a0f9-409a-b26a-628bbfd9349e');
INSERT INTO `jurnal_guru` VALUES (8604, 279, 57, 'Amy Safitri, S.Pd', 11, 15, 'Matematika', '', '', '', '06-05-2026', '21:07:48', '10:45', '12:45', 'Murid-murid memilih sayuran favorit kemudian disajikan dalam bentuk tabel. Lalu mereka belajar membuat piktogram dari tabel sayuran favorit dan juga membuat diagram batang.', 'BAB 6. Piktogram dan Diagram Batang', 1, '11-05-2026', 'Genap', 90, '2025/2026', 'fbf3b9b2-a047-4cf4-bc02-91dde1fc5312');
INSERT INTO `jurnal_guru` VALUES (8605, 276, 57, 'Amy Safitri, S.Pd', 11, 7, 'Bahasa Indonesia', '', '', '', '05-05-2026', '21:09:22', '08:15', '09:15', 'Murid mempelajari tentang konjungsi antar kalimat. Kemudian mengerjakan soal tentang konjungsi antarkalimat dengan cara mencongak (soal didikte oleh guru, murid menuliskan jawaban)', 'BAB 7. Asal Usul', 1, '11-05-2026', 'Genap', 90, '2025/2026', 'bbe6dba0-7604-48ea-8786-0ad560450f31');
INSERT INTO `jurnal_guru` VALUES (8606, 276, 57, 'Amy Safitri, S.Pd', 11, 7, 'Bahasa Indonesia', '', '', '', '05-05-2026', '21:10:16', '08:15', '09:15', 'Murid membuat sebuah cerita melalui rangkaian gambar.', 'BAB 7. Asal-Usul', 1, '11-05-2026', 'Genap', 90, '2025/2026', '6de6ada6-a30b-4743-94c7-5f10c6a94428');
INSERT INTO `jurnal_guru` VALUES (8607, 277, 57, 'Amy Safitri, S.Pd', 11, 7, 'Bahasa Indonesia', '', '', '', '05-05-2026', '21:12:06', '10:45', '11:45', 'Murid membuat sebuah cerita melalui rangkain gambar.', 'BAB 7. Asal-Usul', 1, '11-05-2026', 'Genap', 90, '2025/2026', 'c59dddd8-173f-4c99-8a4e-8273e826c870');
INSERT INTO `jurnal_guru` VALUES (8608, 248, 57, 'Amy Safitri, S.Pd', 11, 21, 'IPAS', '', '', '', '04-05-2026', '21:13:22', '10:45', '12:45', 'Murid mempelajari tentang pencemaran lingkungan, yaitu pencemaran air, tanah dan udara. Mereka belajar dengan menonton video pembelajaran. Sehinggal dapat mengetaui contoh-contoh pencemaran lingkungan, sebab dan akibatnya serta solusi mengatasinya.', 'BAB 8. Menjadi Pahlawan Lingkungan', 1, '11-05-2026', 'Genap', 90, '2025/2026', '4cad8132-f89a-4d45-a59c-b5e3bf6f17b3');
INSERT INTO `jurnal_guru` VALUES (8609, 251, 57, 'Amy Safitri, S.Pd', 11, 16, 'Pendidikan Pancasila', '', '', '', '04-05-2026', '21:14:00', '13:30', '15:00', 'Murid mempelajari tentang sejarah perumusan pancasila. Kemudian bersama-sama mengerjakan latihan soal.', 'BAB 4. Negaraku Indonesia', 1, '11-05-2026', 'Genap', 90, '2025/2026', '4e088d6c-55d3-4452-8910-12531d876b75');
INSERT INTO `jurnal_guru` VALUES (8610, 471, 57, 'Amy Safitri, S.Pd', 11, 25, 'life skill', '', '', '', '01-05-2026', '21:14:24', '08:45', '10:15', 'Libur Hari Buruh Nasional', '', 1, '11-05-2026', 'Genap', 90, '2025/2026', '5b787ccf-0ff0-4acb-b804-e686512031df');
INSERT INTO `jurnal_guru` VALUES (8611, 280, 57, 'Amy Safitri, S.Pd', 11, 14, 'Seni Budaya', '', '', '', '30-04-2026', '21:15:50', '11:45', '12:45', 'Murid mewarnai poster tentang lingkungan. Kemudian menceritakan tentang poster tersebut pada guru. Poster mengandung 2 sisi gambar yang berbeda, yaitu tentang bumi yang rusak dan bumi yang sehat.', 'BAB 6. Membuat Karya Seni yang Berdampak', 1, '11-05-2026', 'Genap', 90, '2025/2026', '369bd88e-a855-4f14-be78-3631f92d8854');
