INSERT INTO `jurnal_guru` VALUES (8850, 276, 57, 'Amy Safitri, S.Pd', 11, 7, 'Bahasa Indonesia', '', '', '', '28-04-2026', '10:54:45', '08:15', '09:15', 'Tes Kemampuan Akademik Kelas VI.\nKelas IV melakukan pembelajaran secara daring dengan mengerjakan tugas:\n1. Membuat puisi dengan tema \"Hobi\"\n2. Puisi minimal 8 baris\n3. Puisi harus memiliki rima, baik rima berurutan (a-a-a- atau a-a-b-b) maupun rima selan', 'BAB 8. Sehatlah Ragaku', 1, '19-05-2026', 'Genap', 90, '2025/2026', '6933742d-ca0e-414b-b4d1-221d0040a345');
INSERT INTO `jurnal_guru` VALUES (8851, 277, 57, 'Amy Safitri, S.Pd', 11, 7, 'Bahasa Indonesia', '', '', '', '28-04-2026', '10:55:00', '10:45', '11:45', 'Tes Kemampuan Akademik Kelas VI.\nKelas IV melakukan pembelajaran secara daring dengan mengerjakan tugas:\n1. Membuat puisi dengan tema \"Hobi\"\n2. Puisi minimal 8 baris\n3. Puisi harus memiliki rima, baik rima berurutan (a-a-a- atau a-a-b-b) maupun rima selan', 'BAB 8. Sehatlah Ragaku', 1, '19-05-2026', 'Genap', 90, '2025/2026', 'b35f8305-c7c8-42be-be17-e02aee741ac5');
INSERT INTO `jurnal_guru` VALUES (8852, 248, 57, 'Amy Safitri, S.Pd', 11, 21, 'IPAS', '', '', '', '27-04-2026', '11:01:07', '10:45', '12:45', 'Tes Kemampuan Akademik Kelas VI.\nKelas IV melakukan pembelajaran secara daring dengan mengerjakan tugas:\n1. Mengidentifikasi masalah pencemaran lingkungan yang ada di sekitar kalian.\n2. Menuliskan 3 masalah pencemaran lingkungan yang ditemukan. Tuliskan S', 'BAB 8. Menjadi Pahlawan Lingkungan', 1, '19-05-2026', 'Genap', 90, '2025/2026', 'db221aa4-c32d-4853-8062-477968da934a');
INSERT INTO `jurnal_guru` VALUES (8853, 251, 57, 'Amy Safitri, S.Pd', 11, 16, 'Pendidikan Pancasila', '', '', '', '27-04-2026', '11:03:37', '13:30', '15:00', 'Tes Kemampuan Akademik Kelas VI.\nKelas IV melakukan pembelajaran secara daring dengan mengerjakan tugas:\n1. Membaca materi di LKS halaman 88-92 tentang Sejarah Perumusan Pancasila\n2. Merangkum tentang Sejarah Perumusan Pancasila\n3. Menulis di buku tulis, ', 'BAB 4. Negaraku Indonesia', 1, '19-05-2026', 'Genap', 90, '2025/2026', '30bc095a-5487-49b6-8052-21e13607c8cc');
INSERT INTO `jurnal_guru` VALUES (8854, 471, 57, 'Amy Safitri, S.Pd', 11, 25, 'life skill', '', '', '', '24-04-2026', '11:15:17', '08:45', '10:15', 'Murid menyaksikan hasil tugas setipa murid. yaitu tugas video mencuci pakaian dii rumah.', '', 1, '19-05-2026', 'Genap', 90, '2025/2026', '05e1ab07-3ae9-4217-839e-c87b33babd36');
