INSERT INTO `jurnal_guru` VALUES (9376, 248, 57, 'Amy Safitri, S.Pd', 11, 21, 'IPAS', '', '', '', '25-05-2026', '11:03:31', '10:45', '12:45', 'Belajar daring\r\n\r\nIPAS: membuat poster sederhana tentang ajakan untuk tidak mencemari lingkungan.\r\n1. Pilih salah satu temanya (pencemaran tanah/air/udara)\r\n2. Gambarlah poster di buku tulis\r\n3. Poster harus mengandung gambar yang sesuai, dan kalimat-kali', '', 1, '15-06-2026', 'Genap', 90, '2025/2026', '0897ad36-7088-4b29-a338-b08cf7014b36');
INSERT INTO `jurnal_guru` VALUES (9377, 251, 57, 'Amy Safitri, S.Pd', 11, 16, 'Pendidikan Pancasila', '', '', '', '25-05-2026', '11:04:05', '13:30', '15:00', 'Belajar daring\r\n\r\nMembuat poster sederhana tentang ajakan untuk tidak mencemari lingkungan.\r\n1. Pilih salah satu temanya (pencemaran tanah/air/udara)\r\n2. Gambarlah poster di buku tulis\r\n3. Poster harus mengandung gambar yang sesuai, dan kalimat-kalimat aj', '', 1, '15-06-2026', 'Genap', 90, '2025/2026', '455351fc-9a03-4b00-a3d5-1eb3f5a486db');
INSERT INTO `jurnal_guru` VALUES (9378, 471, 57, 'Amy Safitri, S.Pd', 11, 25, 'life skill', '', '', '', '22-05-2026', '11:04:27', '08:45', '10:15', 'Belajar daring dikarenakan ada kegiatan PSAJ Kelas 6', '', 1, '15-06-2026', 'Genap', 90, '2025/2026', 'a742d855-6176-47fe-85a4-5743420dc8df');
INSERT INTO `jurnal_guru` VALUES (9379, 280, 57, 'Amy Safitri, S.Pd', 11, 14, 'Seni Budaya', '', '', '', '21-05-2026', '11:06:00', '11:45', '12:45', 'Belajar daring\r\n\r\nSeni Rupa:\r\nMengerjakan LKS halaman 51 yaitu Lembar Aktivitas 3. Penjelasan tugasnya adalah:\r\n• Cari satu contoh karya seni rupa. Bisa karya seni 2D atau 3D yang ada di rumah kemudian di foto, atau bisa mencari di internet atau buku.\r\n• ', '', 1, '15-06-2026', 'Genap', 90, '2025/2026', 'c079f705-a8e9-441f-ac47-fa1318e92f75');
INSERT INTO `jurnal_guru` VALUES (9380, 278, 57, 'Amy Safitri, S.Pd', 11, 3, 'Bahasa Jawa', '', '', '', '20-05-2026', '11:06:51', '08:15', '09:15', 'Belajar daring\r\nMengerjakan latihan soal di LKS halaman 55-58', '', 1, '15-06-2026', 'Genap', 90, '2025/2026', '8a5e331d-e3df-4923-9afe-6bfdcddd49f7');
INSERT INTO `jurnal_guru` VALUES (9381, 279, 57, 'Amy Safitri, S.Pd', 11, 15, 'Matematika', '', '', '', '20-05-2026', '11:07:16', '10:45', '12:45', 'Belajar daring\r\nMatematika:\r\n1. Carilah 7 macam benda berbeda yang ada di dalam rumah kalian.\r\n2. Setiap benda harus berjumlah lebih dari 1.\r\n3. Buatlah rincian data dari 7 macam benda yang sudah kalian temukan dalam bentuk piktogram dan diagram batang.\r\n', '', 1, '15-06-2026', 'Genap', 90, '2025/2026', '5836282d-5226-4f65-a471-bdb40cf42fc2');
INSERT INTO `jurnal_guru` VALUES (9382, 280, 57, 'Amy Safitri, S.Pd', 11, 14, 'Seni Budaya', '', '', '', '16-04-2026', '11:22:41', '11:45', '12:45', 'Murid menilai karya seni yang terdapat pada LKS halaman 46. karya seni tersebut berupa poster tentang keberagaman dan global warming. Murid memberikan pujian, kritik maupun saran.', '', 1, '15-06-2026', 'Genap', 90, '2025/2026', '325e3afe-d910-4382-92db-bc23a76e3e68');
INSERT INTO `jurnal_guru` VALUES (9383, 280, 57, 'Amy Safitri, S.Pd', 11, 14, 'Seni Budaya', '', '', '', '09-04-2026', '11:27:26', '11:45', '12:45', 'Murid mengerjakan latihan soal pada halaman 33-35.', 'BAB 2. Menanggapi Karya Seni Rupa', 1, '15-06-2026', 'Genap', 90, '2025/2026', '9f5aca95-21e5-4b6c-a37d-edcafce2963d');
INSERT INTO `jurnal_guru` VALUES (9384, 280, 57, 'Amy Safitri, S.Pd', 11, 14, 'Seni Budaya', '', '', '', '02-04-2026', '11:29:56', '11:45', '12:45', 'Murid mengelompokkan karya seni rupa 2 dimensi dan 3 dimensi, dengan cara menggunting gambar karya seni kemudian menempelkannya pada buku tulis.', 'BAB 2. Menanggapi Karya Seni Rupa', 1, '15-06-2026', 'Genap', 90, '2025/2026', '04860e7e-7c81-4962-acae-b734adaff984');
